dashboard.definition:
{
	"title": "Hitachi Block Storage Fleet Operations & Performance",
	"description": "Fleet operations dashboard for Hitachi VSP arrays via VSP 360. KPIs, pool capacity trends (Used vs Subscribed TiB, Used% vs Sub Rate%), array IOPS and transfer rate, cache utilization and write pending by CLPR, MPB processor utilization, and port performance (IOPS, response time, utilization, transfer rate).",
	"inputs": {
		"input_vsp360_host": {
			"dataSources": {
				"primary": "ds_populate_vsp360_host"
			},
			"options": {
				"defaultValue": "*",
				"items": [
					{
						"label": "All VSP 360 Hosts",
						"value": "*"
					}
				],
				"token": "vsp360_host_tok"
			},
			"title": "VSP 360 Host",
			"type": "input.dropdown"
		},
		"input_storage_system": {
			"dataSources": {
				"primary": "ds_populate_storage_systems"
			},
			"options": {
				"defaultValue": "*",
				"items": [
					{
						"label": "All Serial Numbers",
						"value": "*"
					}
				],
				"token": "storage_serial_tok"
			},
			"title": "Storage Serial Number",
			"type": "input.dropdown"
		},
		"input_time": {
			"options": {
				"defaultValue": "-24h@h,now",
				"token": "tr_time"
			},
			"title": "Time Range",
			"type": "input.timerange"
		}
	},
	"defaults": {
		"dataSources": {}
	},
	"visualizations": {
		"viz_r1_allocated": {
			"dataSources": {
				"primary": "ds_r1_allocated"
			},
			"options": {
				"backgroundColor": "#FFFBEB",
				"majorColor": "#D97706",
				"majorFontSize": 36,
				"sparklineDisplay": "off",
				"trendDisplay": "off"
			},
			"title": "Allocated (TiB)",
			"type": "splunk.singlevalue"
		},
		"viz_r1_attached_vols": {
			"dataSources": {
				"primary": "ds_r1_attached_vols"
			},
			"options": {
				"backgroundColor": "#F0FDFA",
				"majorColor": "#0D9488",
				"majorFontSize": 36,
				"sparklineDisplay": "off",
				"trendDisplay": "off"
			},
			"title": "Attached Volumes",
			"type": "splunk.singlevalue"
		},
		"viz_r1_capacity": {
			"dataSources": {
				"primary": "ds_r1_capacity"
			},
			"options": {
				"backgroundColor": "#F5F3FF",
				"majorColor": "#7C3AED",
				"majorFontSize": 36,
				"sparklineDisplay": "off",
				"trendDisplay": "off"
			},
			"title": "Capacity (TiB)",
			"type": "splunk.singlevalue"
		},
		"viz_r1_dr": {
			"dataSources": {
				"primary": "ds_r1_dr"
			},
			"options": {
				"backgroundColor": "#EEF2FF",
				"majorColor": "#6366F1",
				"majorFontSize": 36,
				"sparklineDisplay": "off",
				"trendDisplay": "off"
			},
			"title": "Data Reduction",
			"type": "splunk.singlevalue"
		},
		"viz_r1_free": {
			"dataSources": {
				"primary": "ds_r1_free"
			},
			"options": {
				"backgroundColor": "#ECFEFF",
				"majorColor": "#0891B2",
				"majorFontSize": 36,
				"sparklineDisplay": "off",
				"trendDisplay": "off"
			},
			"title": "Free (TiB)",
			"type": "splunk.singlevalue"
		},
		"viz_r1_label": {
			"options": {
				"content": "## Storage System Details"
			},
			"type": "splunk.markdown"
		},
		"viz_r1_model": {
			"dataSources": {
				"primary": "ds_r1_model"
			},
			"options": {
				"backgroundColor": "#EFF6FF",
				"majorColor": "#1E40AF",
				"majorFontSize": 22,
				"sparklineDisplay": "off",
				"trendDisplay": "off"
			},
			"title": "Model",
			"type": "splunk.singlevalue"
		},
		"viz_r1_ports": {
			"dataSources": {
				"primary": "ds_r1_ports"
			},
			"options": {
				"backgroundColor": "#ECFDF5",
				"majorColor": "#047857",
				"majorFontSize": 36,
				"sparklineDisplay": "off",
				"trendDisplay": "off"
			},
			"title": "Ports",
			"type": "splunk.singlevalue"
		},
		"viz_r1_used": {
			"dataSources": {
				"primary": "ds_r1_used"
			},
			"options": {
				"backgroundColor": "#FEF2F2",
				"majorColor": "#DC2626",
				"majorFontSize": 36,
				"sparklineDisplay": "off",
				"trendDisplay": "off"
			},
			"title": "Used (TiB)",
			"type": "splunk.singlevalue"
		},
		"viz_r2_label": {
			"options": {
				"content": "## Pool Capacity Analytics"
			},
			"type": "splunk.markdown"
		},
		"viz_r2_pool_pct": {
			"dataSources": {
				"primary": "ds_r2_pool_pct"
			},
			"options": {
				"areaOpacity": 0.08,
				"legendDisplay": "bottom",
				"lineWidth": 2,
				"nullValueDisplay": "connect",
				"seriesColors": [
					"#DC2626",
					"#047857",
					"#D97706",
					"#7C3AED",
					"#0891B2",
					"#1A56DB",
					"#E11D48",
					"#84CC16",
					"#6366F1",
					"#F97316"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisAbbreviation": "off",
				"yAxisTitleText": "%"
			},
			"title": "Pool Used %",
			"type": "splunk.line"
		},
		"viz_r2_pool_tib": {
			"dataSources": {
				"primary": "ds_r2_pool_tib"
			},
			"options": {
				"areaOpacity": 0.08,
				"legendDisplay": "bottom",
				"lineWidth": 2,
				"nullValueDisplay": "connect",
				"seriesColors": [
					"#7C3AED",
					"#0891B2",
					"#10B981",
					"#F59E0B",
					"#DC2626",
					"#1A56DB",
					"#E11D48",
					"#84CC16",
					"#6366F1",
					"#F97316"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisAbbreviation": "off",
				"yAxisTitleText": "TiB"
			},
			"title": "Pool Used vs Total Capacity (TiB)",
			"type": "splunk.line"
		},
		"viz_r3_iops": {
			"dataSources": {
				"primary": "ds_r3_iops"
			},
			"options": {
				"areaOpacity": 0.15,
				"legendDisplay": "bottom",
				"lineWidth": 2,
				"nullValueDisplay": "zero",
				"seriesColors": [
					"#1A56DB",
					"#7C3AED",
					"#D97706",
					"#DC2626",
					"#047857"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisAbbreviation": "auto",
				"yAxisTitleText": "IOPS"
			},
			"title": "Total IOPS by Array",
			"type": "splunk.area"
		},
		"viz_r3_label": {
			"options": {
				"content": "## Storage Performance Trends"
			},
			"type": "splunk.markdown"
		},
		"viz_r3_xfer": {
			"dataSources": {
				"primary": "ds_r3_xfer"
			},
			"options": {
				"areaOpacity": 0.15,
				"legendDisplay": "bottom",
				"lineWidth": 2,
				"nullValueDisplay": "zero",
				"seriesColors": [
					"#047857",
					"#0891B2",
					"#D97706",
					"#DC2626",
					"#7C3AED"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisAbbreviation": "off",
				"yAxisTitleText": "GiB/s"
			},
			"title": "Transfer Rate by Array (GiB/s)",
			"type": "splunk.area"
		},
		"viz_r4_cache_util": {
			"dataSources": {
				"primary": "ds_r4_cache_util"
			},
			"options": {
				"areaOpacity": 0.1,
				"legendDisplay": "bottom",
				"lineWidth": 2,
				"nullValueDisplay": "zero",
				"seriesColors": [
					"#047857",
					"#0891B2",
					"#D97706",
					"#7C3AED",
					"#1A56DB",
					"#E11D48",
					"#84CC16",
					"#6366F1",
					"#F97316",
					"#14B8A6"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisAbbreviation": "off",
				"yAxisTitleText": "%"
			},
			"title": "Cache Utilization by CLPR (%)",
			"type": "splunk.area"
		},
		"viz_r4_cache_wp": {
			"dataSources": {
				"primary": "ds_r4_cache_wp"
			},
			"options": {
				"areaOpacity": 0.1,
				"legendDisplay": "bottom",
				"lineWidth": 2,
				"nullValueDisplay": "zero",
				"seriesColors": [
					"#DC2626",
					"#F97316",
					"#EAB308",
					"#22C55E",
					"#3B82F6",
					"#8B5CF6",
					"#EC4899",
					"#14B8A6",
					"#0EA5E9",
					"#D946EF"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisAbbreviation": "off",
				"yAxisTitleText": "%"
			},
			"title": "Cache Write Pending Rate by CLPR (%)",
			"type": "splunk.area"
		},
		"viz_r4_label": {
			"options": {
				"content": "## Cache & Processor Utilization"
			},
			"type": "splunk.markdown"
		},
		"viz_r4_trend": {
			"dataSources": {
				"primary": "ds_r4_trend"
			},
			"options": {
				"areaOpacity": 0.08,
				"legendDisplay": "bottom",
				"lineWidth": 2,
				"nullValueDisplay": "zero",
				"seriesColors": [
					"#DC2626",
					"#F97316",
					"#EAB308",
					"#22C55E",
					"#3B82F6",
					"#8B5CF6",
					"#EC4899",
					"#14B8A6",
					"#0EA5E9",
					"#D946EF",
					"#84CC16",
					"#6366F1"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisAbbreviation": "off",
				"yAxisTitleText": "%"
			},
			"title": "MPB Utilization per Processor (%)",
			"type": "splunk.area"
		},
		"viz_r5_iops": {
			"dataSources": {
				"primary": "ds_r5_iops_line"
			},
			"options": {
				"areaOpacity": 0,
				"legendDisplay": "bottom",
				"lineWidth": 2,
				"nullValueDisplay": "zero",
				"seriesColors": [
					"#1A56DB",
					"#DC2626",
					"#047857",
					"#D97706",
					"#7C3AED",
					"#0891B2",
					"#E11D48",
					"#84CC16",
					"#6366F1",
					"#F97316"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisAbbreviation": "auto",
				"yAxisTitleText": "IOPS"
			},
			"title": "Port IOPS (Top 10)",
			"type": "splunk.line"
		},
		"viz_r5_label": {
			"options": {
				"content": "## Top Port Performance Trends"
			},
			"type": "splunk.markdown"
		},
		"viz_r5_resp": {
			"dataSources": {
				"primary": "ds_r5_resp_line"
			},
			"options": {
				"areaOpacity": 0,
				"legendDisplay": "bottom",
				"lineWidth": 2,
				"nullValueDisplay": "zero",
				"seriesColors": [
					"#1A56DB",
					"#DC2626",
					"#047857",
					"#D97706",
					"#7C3AED",
					"#0891B2",
					"#E11D48",
					"#84CC16",
					"#6366F1",
					"#F97316"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisAbbreviation": "off",
				"yAxisTitleText": "ms"
			},
			"title": "Port Response Time ms (Top 10)",
			"type": "splunk.line"
		},
		"viz_r5_util": {
			"dataSources": {
				"primary": "ds_r5_util_line"
			},
			"options": {
				"areaOpacity": 0,
				"legendDisplay": "bottom",
				"lineWidth": 2,
				"nullValueDisplay": "zero",
				"seriesColors": [
					"#1A56DB",
					"#DC2626",
					"#047857",
					"#D97706",
					"#7C3AED",
					"#0891B2",
					"#E11D48",
					"#84CC16",
					"#6366F1",
					"#F97316"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisAbbreviation": "off",
				"yAxisTitleText": "%"
			},
			"title": "Port Utilization % (Top 10)",
			"type": "splunk.line"
		},
		"viz_r6_port_xfer": {
			"dataSources": {
				"primary": "ds_r6_port_xfer"
			},
			"options": {
				"areaOpacity": 0,
				"legendDisplay": "bottom",
				"lineWidth": 2,
				"nullValueDisplay": "zero",
				"seriesColors": [
					"#047857",
					"#0891B2",
					"#D97706",
					"#DC2626",
					"#7C3AED",
					"#1A56DB",
					"#E11D48",
					"#84CC16",
					"#6366F1",
					"#F97316"
				],
				"xAxisTitleVisibility": "hide",
				"yAxisAbbreviation": "off",
				"yAxisTitleText": "MiB/s"
			},
			"title": "Port Transfer Rate Trend (Top 10, MiB/s)",
			"type": "splunk.line"
		}
	},
	"dataSources": {
		"ds_populate_vsp360_host": {
			"name": "populate_vsp360_host",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidStorage\" attribute_name=\"name\" | dedup vsp360_host sortby -_time | where isnotnull(vsp360_host) | table vsp360_host | rename vsp360_host as vsp360_host_tok | sort + vsp360_host_tok",
				"queryParameters": {
					"earliest": "-30d@d",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_populate_storage_systems": {
			"name": "populate_storage_systems",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidStorage\" attribute_name=\"name\" | dedup storage_serial sortby -_time | where isnotnull(storage_serial) | eval label=storage_name.\" (\".storage_serial.\")\" | table storage_serial label | rename storage_serial as storage_serial_tok | sort + label",
				"queryParameters": {
					"earliest": "-30d@d",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_r1_allocated": {
			"name": "r1_allocated",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidLU\" attribute_name=\"ldev\" | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eventstats max(_time) as _latest_t | where _time >= (_latest_t - 1800) | dedup signature sortby -_time | eval ldev_key=storage_serial.\"-\".value | dedup ldev_key | fields storage_serial ldev_key | join type=inner ldev_key     [search index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\"      resource_type=\"raidLdev\" attribute_name=\"ldevCapacityGB\"      | eventstats max(_time) as _latest_t      | where _time >= (_latest_t - 1800)      | dedup signature sortby -_time      | eval ldev_key=storage_serial.\"-\".instance_id      | eval cap=tonumber(value)      | where isnotnull(cap)      | fields ldev_key cap] | stats sum(cap) as sum_gib | eval alloc_tib=tostring(round(sum_gib/1024, 1)) | table alloc_tib",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r1_attached_vols": {
			"name": "r1_attached_vols",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidLU\" attribute_name=\"ldev\" | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eventstats max(_time) as _latest_t | where _time >= (_latest_t - 1800) | dedup signature sortby -_time | eval ldev_key=storage_serial.\"-\".value | dedup ldev_key | stats dc(ldev_key) as cnt | eval total=tostring(cnt) | table total",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r1_capacity": {
			"name": "r1_capacity",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidPool\" attribute_name=\"totalCapacityInGB\" | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | where isnotnull(value) | eventstats max(_time) as _latest_t | where _time >= (_latest_t - 1800) | dedup storage_serial, instance_id sortby -_time | eval total_gib=tonumber(value) | where isnotnull(total_gib) | stats sum(total_gib) as sum_gib | eval capacity_tib=tostring(round(sum_gib/1024, 1)) | table capacity_tib",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r1_dr": {
			"name": "r1_dr",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidStorage\" attribute_name IN (\"softwareSavingRatio\",\"totalEfficiencyRatio\") | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eventstats max(_time) as _latest_t | where _time >= (_latest_t - 1800) | dedup storage_serial, attribute_name sortby -_time | eval v=tonumber(value) | stats latest(eval(if(attribute_name=\"softwareSavingRatio\",v,null()))) as ssr,         latest(eval(if(attribute_name=\"totalEfficiencyRatio\",v,null()))) as ter         by storage_serial | head 1 | eval ratio=if(isnotnull(ssr) AND ssr>0, ssr,     if(isnotnull(ter) AND ter>0 AND ter<99999, ter, null())) | eval display=if(isnotnull(ratio), round(ratio, 1).\" : 1\", \"N/A\") | table display",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r1_free": {
			"name": "r1_free",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidPool\" attribute_name=\"availableCapacityInGB\" | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | where isnotnull(value) | eventstats max(_time) as _latest_t | where _time >= (_latest_t - 1800) | dedup storage_serial, instance_id sortby -_time | eval free_gib=tonumber(value) | where isnotnull(free_gib) | stats sum(free_gib) as sum_gib | eval free_tib=tostring(round(sum_gib/1024, 1)) | table free_tib",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r1_model": {
			"name": "r1_model",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidStorage\" attribute_name=\"modelName\" | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eventstats max(_time) as _latest_t | where _time >= (_latest_t - 1800) | dedup storage_serial sortby -_time | head 1 | eval model=coalesce(value, storage_model, \"N/A\") | table model",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r1_ports": {
			"name": "r1_ports",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidPort\" attribute_name=\"name\" | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eventstats max(_time) as _latest_t | where _time >= (_latest_t - 1800) | dedup signature sortby -_time | stats dc(signature) as cnt | eval total=tostring(cnt) | table total",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r1_used": {
			"name": "r1_used",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidPool\" attribute_name=\"usedCapacityInGB\" | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | where isnotnull(value) | eventstats max(_time) as _latest_t | where _time >= (_latest_t - 1800) | dedup storage_serial, instance_id sortby -_time | eval used_gib=tonumber(value) | where isnotnull(used_gib) | stats sum(used_gib) as sum_gib | eval used_tib=round(sum_gib/1024, 1) | table used_tib",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r2_pool_pct": {
			"name": "r2_pool_pct",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidPool\" attribute_name=\"usageRate\" | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | where isnotnull(value) | eval used_pct=tonumber(value), pool_key=storage_serial.\"-\".instance_id | join type=left pool_key     [search index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\"      resource_type=\"raidPool\" attribute_name=\"poolName\"      | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\")      | dedup storage_serial, instance_id sortby -_time      | eval pool_key=storage_serial.\"-\".instance_id      | eval pool_label=value.\" (\".storage_serial.\")\"      | fields pool_key pool_label] | eval pool_label=coalesce(pool_label, \"Pool-\".instance_id.\" (\".storage_serial.\")\") | timechart span=1h latest(used_pct) by pool_label limit=20 | filldown | reverse | filldown | reverse",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r2_pool_tib": {
			"name": "r2_pool_tib",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\" resource_type=\"raidPool\" attribute_name IN (\"usedCapacityInGB\",\"totalCapacityInGB\") | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | where isnotnull(value) | eval pool_key=storage_serial.\"-\".instance_id | join type=left pool_key     [search index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:config\"      resource_type=\"raidPool\" attribute_name=\"poolName\"      | where (storage_serial=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\")      | dedup storage_serial, instance_id sortby -_time      | eval pool_key=storage_serial.\"-\".instance_id      | eval pool_label=value.\" (\".storage_serial.\")\"      | fields pool_key pool_label] | eval pool_label=coalesce(pool_label, \"Pool-\".instance_id.\" (\".storage_serial.\")\") | eval metric_label=if(attribute_name=\"usedCapacityInGB\",\"Used\",\"Total\") | eval series=pool_label.\" - \".metric_label | eval tib=round(tonumber(value)/1024, 2) | timechart span=1h latest(tib) by series limit=20 | filldown | reverse | filldown | reverse",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r3_iops": {
			"name": "r3_iops",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:perf\" resource_type=\"raidStorage\" | spath input=_raw path=metric_name output=mn | spath input=_raw path=value output=val | spath input=_raw path=storage_serial output=ser | spath input=_raw path=storage_name output=arr_name | where mn=\"totalIOPS\" | where (ser=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eval iops=tonumber(val) | eval label=arr_name.\" (\".ser.\")\" | timechart span=5m avg(iops) by label limit=10 | fillnull value=0",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r3_xfer": {
			"name": "r3_xfer",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:perf\" resource_type=\"raidStorage\" | spath input=_raw path=metric_name output=mn | spath input=_raw path=value output=val | spath input=_raw path=storage_serial output=ser | spath input=_raw path=storage_name output=arr_name | where mn=\"transferRate\" | where (ser=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eval gibps=round(tonumber(val)/1048576, 2) | eval label=arr_name.\" (\".ser.\")\" | timechart span=5m avg(gibps) by label limit=10 | fillnull value=0",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r4_cache_util": {
			"name": "r4_cache_util",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:perf\" resource_type=\"raidClpr\" | spath input=_raw path=metric_name output=mn | spath input=_raw path=value output=val | spath input=_raw path=storage_serial output=ser | spath input=_raw path=instance_id output=clpr_id | where mn=\"utilization\" | where (ser=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eval util=tonumber(val) | eval label=\"CLPR-\".clpr_id | timechart span=1m avg(util) by label limit=10 | fillnull value=0",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
