			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:perf\" resource_type=\"raidClpr\" | spath input=_raw path=metric_name output=mn | spath input=_raw path=value output=val | spath input=_raw path=storage_serial output=ser | spath input=_raw path=instance_id output=clpr_id | where mn=\"writePendingRate\" | where (ser=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eval wp=tonumber(val) | eval label=\"CLPR-\".clpr_id | timechart span=1m avg(wp) by label limit=10 | fillnull value=0",
