				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:perf\" resource_type=\"raidMPB\" | spath input=_raw path=metric_name output=mn | spath input=_raw path=value output=val | spath input=_raw path=storage_serial output=ser | spath input=_raw path=instance_id output=mpb_id | where mn=\"utilization\" | where (ser=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eval util=round(tonumber(val), 1) | timechart span=5m avg(util) by mpb_id limit=15 | fillnull value=0",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r5_iops_line": {
			"name": "r5_port_iops_line",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:perf\" resource_type=\"raidPort\" | spath input=_raw path=metric_name output=mn | spath input=_raw path=value output=val | spath input=_raw path=storage_serial output=ser | spath input=_raw path=instance_id output=port_id | where mn=\"totalIOPS\" | where (ser=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eval val=tonumber(val) | eventstats avg(val) as avg_iops_port by port_id | sort 0 - avg_iops_port | timechart span=5m avg(val) by port_id limit=10 useother=false | fillnull value=0",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_r5_resp_line": {
			"name": "r5_port_resp_line",
			"options": {
				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:perf\" resource_type=\"raidPort\" | spath input=_raw path=metric_name output=mn | spath input=_raw path=value output=val | spath input=_raw path=storage_serial output=ser | spath input=_raw path=instance_id output=port_id | where mn=\"responseTime\" | where (ser=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eval val=tonumber(val) | eventstats avg(val) as avg_resp by port_id | sort 0 - avg_resp | timechart span=5m avg(val) by port_id limit=10 useother=false | fillnull value=0",
				"queryParameters": {
					"earliest": "$tr_time.earliest$",
					"latest": "$tr_time.latest$"
				}
