				"query": "index=\"hitachicsad\" sourcetype=\"hitachi:vspblock:perf\" resource_type=\"raidPort\" | spath input=_raw path=metric_name output=mn | spath input=_raw path=value output=val | spath input=_raw path=storage_serial output=ser | spath input=_raw path=instance_id output=port_id | where mn=\"transferRate\" | where (ser=\"$storage_serial_tok$\" OR \"$storage_serial_tok$\"=\"*\") | eval mib=round(tonumber(val)/1024, 2) | eventstats avg(mib) as avg_mib by port_id | sort 0 - avg_mib | timechart span=5m avg(mib) by port_id limit=10 useother=false | fillnull value=0",
